final:
module top_module (
    input z,
    input x,
    input j,
    input l,
    output reg gg
);
    always @(*) begin
        case ({z, x, j, l})
            4'b0000: gg = 1'b1;
            4'b0011: gg = 1'b0;
            4'b1101: gg = 1'b1;
            4'b1110: gg = 1'b1;
            4'b0111: gg = 1'b0;
            4'b1010: gg = 1'b1;
            4'b0101: gg = 1'b1;
            4'b0001: gg = 1'b1;
            4'b0110: gg = 1'b0;
            4'b1001: gg = 1'b0;
            4'b1111: gg = 1'b1;
            4'b0100: gg = 1'b1;
            4'b1011: gg = 1'b1;
            4'b0010: gg = 1'b1;
            4'b1000: gg = 1'b1;
            4'b1100: gg = 1'b0;
        endcase
    end
endmodule
